import{_ as a,o as t,c as i,a2 as o}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Epic: Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"epics/analytics.md","filePath":"epics/analytics.md"}'),c={name:"epics/analytics.md"};function s(l,e,n,d,r,p){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="epic-analytics" tabindex="-1">Epic: Analytics <a class="header-anchor" href="#epic-analytics" aria-label="Permalink to &quot;Epic: Analytics&quot;">​</a></h1><blockquote><p>Self-hosted, privacy-first usage analytics — all data stays on the instance, DNT/GPC are hard-blocked, and collection is off by default.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>📋 Planned</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Analytics ships as a platform plugin (<code>fs.sovereign.analytics</code>) so operators who want no analytics at all can simply disable it in Console. Phase 1 delivers server-side page-view recording via middleware and a <code>sdk.analytics.track()</code> surface for custom plugin events, with an aggregate dashboard using native <code>&lt;canvas&gt;</code> charts. Phase 2 adds a self-hosted client-side click and scroll tracking script and a heatmap visualization — no third-party CDN ever involved.</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="📋-6-1-—-analytics-phase-1-—-plugin-scaffold-server-side-infrastructure-rfc-0030" tabindex="-1">📋 6.1 — Analytics, Phase 1 — Plugin scaffold + server-side infrastructure (RFC 0030) <a class="header-anchor" href="#📋-6-1-—-analytics-phase-1-—-plugin-scaffold-server-side-infrastructure-rfc-0030" aria-label="Permalink to &quot;📋 6.1 — Analytics, Phase 1 — Plugin scaffold + server-side infrastructure (RFC 0030)&quot;">​</a></h4><p><strong>Goal:</strong> Introduce a self-hosted, operator-controlled analytics system as a new <strong>platform plugin</strong> (<code>plugins/analytics/</code>, id <code>fs.sovereign.analytics</code>). All data stays on the instance. Page views are recorded server-side by the middleware (hard DNT/GPC block). Plugins can emit custom analytics events via <code>sdk.analytics.track()</code>. Admins view aggregate usage data in the Analytics plugin&#39;s Dashboard. Data collection is <strong>off by default</strong> — enabled explicitly in Analytics → Settings. Operators who want no analytics at all can disable the plugin in Console → Plugin Management.</p><p><strong>Deliverables:</strong></p><ul><li><code>plugins/analytics/</code> scaffold: <code>manifest.json</code> (<code>type: platform</code>, <code>shell: default</code>, <code>routePrefix: /analytics</code>, <code>adminOnly: true</code>, <code>database: shared</code>, <code>permissions: [&quot;auth:session&quot;, &quot;db:readWrite&quot;]</code>), <code>icon.svg</code>, <code>app/layout.tsx</code> (Dashboard / Settings nav), <code>app/page.tsx</code> (Dashboard), <code>app/settings/page.tsx</code> (collection toggle, retention dropdown, export, clear-all), empty <code>db/schema.ts</code>, <code>package.json</code>.</li><li><code>packages/db</code>: <code>analytics_page_views</code> + <code>analytics_events</code> table schemas for both SQLite and Postgres dialects; drizzle-kit migrations; DB helpers <code>recordPageView()</code>, <code>recordAnalyticsEvent()</code>, <code>queryAnalyticsAggregates()</code>, <code>cleanupOldAnalyticsRows()</code>; bootstrap seeds four new <code>platform_settings</code> keys: <code>analytics_collection_enabled</code> (<code>&#39;false&#39;</code>), <code>analytics_retention_days</code> (<code>&#39;90&#39;</code>), <code>analytics_daily_salt</code> (auto-generated), <code>analytics_salt_date</code> (today).</li><li><code>packages/manifest</code>: new <code>analytics:write</code> permission string in the manifest schema.</li><li><code>packages/sdk</code>: <code>sdk.analytics.track(event, properties?)</code> and <code>sdk.analytics.isEnabled()</code> in the experimental group; <code>SdkHost</code> gains <code>analytics</code> key.</li><li><code>runtime</code>: <ul><li><code>GET /api/analytics/config</code> — edge-cached (60 s); reads analytics plugin&#39;s <code>plugin_status.is_enabled</code> AND <code>analytics_collection_enabled</code> platform setting. Returns <code>{ enabled: bool, salt, saltDate, retentionDays }</code>.</li><li>Middleware page-view recording: fetch analytics config at request start, check <code>DNT</code>/<code>Sec-GPC</code> headers (hard block on either), compute daily-rotating session hash (<code>SHA-256(session_token + daily_salt)</code>), fire-and-forget <code>POST /api/analytics/internal/page-view</code> (non-blocking).</li><li><code>POST /api/analytics/internal/page-view</code> — Node-runtime write route (admin-key-authed).</li><li><code>GET /api/admin/analytics</code> — aggregate query endpoint (<code>health:view</code>-gated); supports <code>?range=7d|30d|90d</code> and <code>?type=pageviews|events|sessions</code>.</li><li><code>&#39;analytics&#39;</code> added to <code>RESERVED_API_SEGMENTS</code>; dir-parity test passes.</li><li>Cleanup runner in <code>runtime/instrumentation.ts</code> <code>register()</code>: <code>cleanupOldAnalyticsRows()</code>.</li><li>SDK host <code>analytics</code> implementation: 60 s in-process cache for enabled state; checks plugin status + collection flag + DNT header; namespaces event to <code>&lt;pluginId&gt;.&lt;event&gt;</code>.</li></ul></li><li><code>plugins/analytics/app/page.tsx</code>: Dashboard with active sessions/day bar chart, page views by plugin bar chart, top pages table, custom events table. Native <code>&lt;canvas&gt;</code> charts — no charting library dependency.</li><li><code>plugins/analytics/app/settings/page.tsx</code>: collection toggle (writes <code>analytics_collection_enabled</code>), retention dropdown (30/60/90/180 days), export button (<code>GET /api/admin/analytics?format=csv</code>), clear-all destructive button.</li><li><code>plugins/console</code>: Health page gains a &quot;View analytics →&quot; link to <code>/analytics</code>.</li><li>Docs: <ul><li><code>plugin-development.md</code>: <code>sdk.analytics</code> surface documented; <code>analytics:write</code> permission in manifest reference table; plugin custom-event pattern + PII warning.</li><li><code>self-hosting.md</code>: <code>analytics_collection_enabled</code>, <code>analytics_retention_days</code> settings documented.</li><li><code>sdk-stability.md</code>: <code>sdk.analytics</code> added to the experimental-implemented group.</li><li><code>packages/sdk/CHANGELOG.md</code>: minor entry.</li><li>Docs-parity test must pass for <code>analytics:write</code> permission and <code>sdk.analytics</code>.</li></ul></li></ul><p><strong>Dependencies:</strong> None (independent post-v1 task)</p><p><strong>SRS reference:</strong> RFC 0030</p><p><strong>Review checklist:</strong></p><ul><li><code>GET /analytics</code> (admin session) → Dashboard renders</li><li><code>GET /analytics</code> (platform:user session) → 403</li><li>Analytics plugin visible in Console → Plugin Management with enable/disable toggle</li><li>Collection off by default: visit pages → no rows in <code>analytics_page_views</code></li><li>Enable collection in Analytics → Settings; visit plugin page → row in <code>analytics_page_views</code></li><li><code>curl -H &quot;DNT: 1&quot; http://localhost:3000/launcher</code> → no row inserted (hard block)</li><li><code>curl -H &quot;Sec-GPC: 1&quot; http://localhost:3000/launcher</code> → no row inserted (hard block)</li><li>Plugin WITH <code>analytics:write</code> permission: <code>sdk.analytics.track(&#39;feature.used&#39;, {})</code> → row in <code>analytics_events</code> with namespaced <code>event_name</code></li><li>Plugin WITHOUT <code>analytics:write</code> permission: <code>sdk.analytics.track()</code> → silent no-op, no row, no error</li><li>Disable analytics plugin in Console → Plugin Management: <code>GET /analytics</code> → 404; <code>GET /api/analytics/config</code> → <code>{ enabled: false }</code>; <code>sdk.analytics.track()</code> from any plugin → no-op</li><li>Retention cleanup: set <code>analytics_retention_days</code> to <code>1</code>, restart → old rows deleted at startup</li><li><code>pnpm format:check &amp;&amp; pnpm lint &amp;&amp; pnpm typecheck &amp;&amp; pnpm test</code> all pass</li><li>Docs-parity test passes: <code>analytics:write</code> + <code>sdk.analytics</code> documented</li></ul><hr><h4 id="📋-6-2-—-analytics-phase-2-—-client-side-click-tracking-heatmaps-rfc-0030" tabindex="-1">📋 6.2 — Analytics, Phase 2 — Client-side click tracking + heatmaps (RFC 0030) <a class="header-anchor" href="#📋-6-2-—-analytics-phase-2-—-client-side-click-tracking-heatmaps-rfc-0030" aria-label="Permalink to &quot;📋 6.2 — Analytics, Phase 2 — Client-side click tracking + heatmaps (RFC 0030)&quot;">​</a></h4><p><strong>Goal:</strong> Extend the analytics plugin with client-side click and scroll tracking (collected by a self-hosted JS snippet served from the runtime — never a third-party CDN) and a heatmap visualization in the Analytics plugin&#39;s Heatmap tab. The client script checks <code>navigator.doNotTrack</code> and <code>navigator.globalPrivacyControl</code> before initializing — hard block if either is set.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/db</code>: <code>analytics_click_events</code> + <code>analytics_scroll_events</code> table schemas for both dialects; drizzle-kit migrations; DB helpers for batch insert and heatmap aggregate queries.</li><li><code>runtime</code>: <ul><li><code>POST /api/analytics/event</code> — client-side event receiver: session-cookie-authed, re-checks DNT/GPC, computes session hash, batch-inserts click and scroll rows.</li><li><code>GET /api/analytics/script.js</code> — self-hosted analytics client script: returns empty 200 when analytics is disabled or collection is off; otherwise returns the minified tracking script (~3 KB). Checks <code>navigator.doNotTrack</code> / <code>navigator.globalPrivacyControl</code> before attaching any listeners — exits immediately if either is truthy.</li><li>Root layout (<code>runtime/app/layout.tsx</code>): <code>&lt;Script src=&quot;/api/analytics/script.js&quot; strategy=&quot;afterInteractive&quot;&gt;</code> (excluded from session gate).</li><li><code>GET /api/admin/analytics?type=clicks&amp;path=&lt;pathname&gt;</code> and <code>?type=scroll</code> — heatmap aggregate queries.</li></ul></li><li><code>plugins/analytics/app/heatmap/page.tsx</code>: <strong>Heatmap</strong> tab added to Analytics plugin: <ul><li>Plugin selector + path input.</li><li>Click heatmap rendered on <code>&lt;canvas&gt;</code> as radial-gradient density overlay (blue → yellow → red).</li><li>Optional <code>&lt;iframe sandbox=&quot;allow-same-origin allow-scripts&quot; style=&quot;pointer-events:none&quot;&gt;</code> for live page background.</li><li>Scroll depth segmented bar (% of sessions reaching 25/50/75/100%).</li><li>Date range filter.</li></ul></li><li>CSP: <code>connect-src &#39;self&#39;</code> already covers <code>/api/analytics/event</code> — no change needed.</li></ul><p><strong>Dependencies:</strong> Task 1.0.5</p><p><strong>SRS reference:</strong> RFC 0030</p><p><strong>Review checklist:</strong></p><ul><li>Load a plugin page, click several elements, scroll to bottom; navigate away; confirm rows appear in <code>analytics_click_events</code> and <code>analytics_scroll_events</code></li><li>Form field clicks (<code>&lt;input&gt;</code>, <code>&lt;textarea&gt;</code>) produce no <code>element_selector</code> recording</li><li>Browser with <code>navigator.doNotTrack = &#39;1&#39;</code>: reload — no network request to <code>/api/analytics/event</code> (verify in DevTools Network tab)</li><li><code>GET /api/analytics/script.js</code> with analytics disabled → empty body, 200 OK</li><li>Analytics plugin Heatmap tab: select a plugin + path → canvas renders click density gradient</li><li>Scroll depth bar: reflects actual scrolling depth from test session</li><li><code>pnpm format:check &amp;&amp; pnpm lint &amp;&amp; pnpm typecheck &amp;&amp; pnpm test</code> all pass</li></ul><hr><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0030-privacy-first-analytics.html">RFC 0030 — Privacy-first analytics</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../plugin-development.html">plugin-development.md — <code>sdk.analytics</code> (post-v1)</a></li><li><a href="./../self-hosting.html">self-hosting.md — Analytics settings (post-v1)</a></li></ul>',29)])])}const h=a(c,[["render",s]]);export{u as __pageData,h as default};
